 \\ 
 \mathsf {add} { \mathopen {} \left ( m,n+1 \right ) \mathclose {}}  &=  \mathsf {add} { \mathopen {} \left ( m,n \right ) \mathclose {}} +1
\end {aligned}

\begin {aligned}
 \Sigma  & \colon   \mathbb {N} \to \mathbb {N} \\ 
 \Sigma { \mathopen {} \left ( 0 \right ) \mathclose {}}  &= 0 \\ 
 \Sigma { \mathopen {} \left ( n+1 \right ) \mathclose {}}  &=  \mathsf {add} { \mathopen {} \left ( n, \Sigma { \mathopen {} \left ( n \right ) \mathclose {}} \right ) \mathclose {}} 
\end {aligned}

\begin {aligned}
 \mathbf { \rho }_{ a , f } { \mathopen {} \left ( 0 \right ) \mathclose {}}  &= a \\ 
 \mathbf { \rho }_{ a , f } { \mathopen {} \left ( n+1 \right ) \mathclose {}}  &= f { \mathopen {} \left ( n, \mathbf { \rho }_{ a , f } { \mathopen {} \left ( n \right ) \mathclose {}} \right ) \mathclose {}} 
\end {aligned}

\mathord { \# } { \mathrm {Bij} { \mathopen {} \left ( A , B \right ) \mathclose {}} } =
\begin {cases}
0 & \text {if }  \mathord { \# } {A} \not = \mathord { \# } {B} \\ 
n!& \text {if }  \mathord { \# } {A}= \mathord { \# } {B}=n
\end {cases}

\begin {aligned}
  \Phi { \mathopen {} \left ( \Phi ^{-1} { \mathopen {} \left ( P \right ) \mathclose {}} \right ) \mathclose {}}  &=
  { \mathopen {} \left \{ 
    { \mathopen {} \left  [ a \right  ] \mathclose {}} _{ \Phi ^{-1} { \mathopen {} \left ( P \right ) \mathclose {}} } 
  \, \middle \vert \, a \in  A \right \} \mathclose {}} 
  \\ 
 &=
  { \mathopen {} \left \{ 
    { \mathopen {} \left \{ x \in  A \, \middle \vert \, x  \mathrel { { \mathopen {} \left ( \Phi ^{-1} { \mathopen {} \left ( P \right ) \mathclose {}} \right ) \mathclose {}} } a \right \} \mathclose {}} 
  \, \middle \vert \, a \in  A \right \} \mathclose {}} 
  \\ 
 &=
  { \mathopen {} \left \{ 
    { \mathopen {} \left \{ x \in  A \, \middle \vert \, 
      \exists  b \in  P \mathpunct {.} 
     x \in  b  \land  a  \in  b
    \right \} \mathclose {}} 
  \, \middle \vert \, a \in  A \right \} \mathclose {}} 
\end {aligned}

\begin {aligned}
 x \mathrel { { \mathopen {} \left ( \Phi ^{-1} { \mathopen {} \left ( \Phi { \mathopen {} \left ( E \right ) \mathclose {}} \right ) \mathclose {}} \right ) \mathclose {}} }y
 & \Longleftrightarrow 
  \exists  b \in   \Phi { \mathopen {} \left ( E \right ) \mathclose {}} \mathpunct {.} 
 x \in  b  \land  y  \in  b
  \\ 
 & \Longleftrightarrow 
  \exists  a \in  A \mathpunct {.} 
 x \in   { \mathopen {} \left  [ a \right  ] \mathclose {}} _{ E } 
  \land 
 y \in   { \mathopen {} \left  [ a \right  ] \mathclose {}} _{ E } 
  \\ 
 & \Longleftrightarrow 
  \exists  a  \in  A \mathpunct {.} 
 x \mathrel {E}a \land  y \mathrel {E}a
  \\ 
 & \Longleftrightarrow 
 x  \mathrel {E} y
\end {aligned}

