\chi _S { \mathopen {} \left ( a \right ) \mathclose {}}  =  \begin {cases}
1 &  \text {if } a  \in  S \\ 
0 &  \text {if } a  \not \in  S
\end {cases}

\begin {aligned}
  { \mathopen {} \left  [ \chi _{S} \right  ] \mathclose {}}  &=  { \mathopen {} \left \{ a \in  A \, \middle \vert \, \chi _S { \mathopen {} \left ( a \right ) \mathclose {}} =1 \right \} \mathclose {}} \\ 
 &=  { \mathopen {} \left \{ a \in  A \, \middle \vert \, a \in  S \right \} \mathclose {}} \\ 
 &= S
\end {aligned}

 \begin {aligned}
 \chi _{ { \mathopen {} \left  [ \phi \right  ] \mathclose {}} } { \mathopen {} \left ( a \right ) \mathclose {}}  &=  \begin {cases}
 1 &  \text {if } a  \in   { \mathopen {} \left  [ \phi \right  ] \mathclose {}} \\ 
 0 &  \text {if } a  \not \in { \mathopen {} \left  [ \phi \right  ] \mathclose {}} 
 \end {cases}
 \\ 
&=
 \begin {cases}
 1 & \text {if }  \phi { \mathopen {} \left ( a \right ) \mathclose {}} =1 \\ 
 0 & \text {if }  \phi { \mathopen {} \left ( a \right ) \mathclose {}} \not =1
 \end {cases}
 \\ 
&=
 \begin {cases}
 1 & \text {if }  \phi { \mathopen {} \left ( a \right ) \mathclose {}} =1 \\ 
 0 & \text {if }  \phi { \mathopen {} \left ( a \right ) \mathclose {}} =0
 \end {cases}
 \\ 
&=  \phi { \mathopen {} \left ( a \right ) \mathclose {}} 
 \end {aligned}

\begin {aligned}
 \mathcal {P} { \mathopen {} \left ( X \right ) \mathclose {}} \times { \mathopen {} \left  [ 2 \right  ] \mathclose {}}  &=  \mathcal {P} { \mathopen {} \left ( X \right ) \mathclose {}} \times { \mathopen {} \left ( { \mathopen {} \left  [ 1 \right  ] \mathclose {}} + { \mathopen {} \left  [ 1 \right  ] \mathclose {}} \right ) \mathclose {}} \\ 
&=  \mathcal {P} { \mathopen {} \left ( X \right ) \mathclose {}} \times { \mathopen {} \left  [ 1 \right  ] \mathclose {}} + \mathcal {P} { \mathopen {} \left ( X \right ) \mathclose {}} \times { \mathopen {} \left  [ 1 \right  ] \mathclose {}} \\ 
&=  \mathcal {P} { \mathopen {} \left ( X \right ) \mathclose {}} + \mathcal {P} { \mathopen {} \left ( X \right ) \mathclose {}} 
\end {aligned}

\begin {aligned}
I & \colon { \mathopen {} \left  [ m \right  ] \mathclose {}} \times { \mathopen {} \left  [ n \right  ] \mathclose {}} \to   { \mathopen {} \left  [ m \cdot  n \right  ] \mathclose {}} \\ 
I { \mathopen {} \left ( i,j \right ) \mathclose {}}  &= m \cdot  j + i
\end {aligned}

\begin {aligned}
I & \colon { \mathopen {} \left  [ m \right  ] \mathclose {}} + { \mathopen {} \left  [ n \right  ] \mathclose {}}   \to   { \mathopen {} \left  [ m+n \right  ] \mathclose {}} \\ 
I { \mathopen {} \left ( 0,i<m \right ) \mathclose {}}  &= i \\ 
I { \mathopen {} \left ( 1,j<n \right ) \mathclose {}}  &= m+j
\end {aligned}

I { \mathopen {} \left ( k \right ) \mathclose {}}  =
 \begin {cases}
  { \mathopen {} \left ( 0,k \right ) \mathclose {}}  & \text {when } k < m \\ 
  { \mathopen {} \left ( 1,k-m \right ) \mathclose {}}  & \text {when } k  \geq  m
 \end {cases}

 \begin {aligned}
e' { \mathopen {} \left ( 0 \right ) \mathclose {}}  &= 0 \\ 
e' { \mathopen {} \left ( n+1 \right ) \mathclose {}}  &= e { \mathopen {} \left ( n \right ) \mathclose {}} 
 \end {aligned}

e' { \mathopen {} \left ( i \right ) \mathclose {}}  =
 \begin {cases}
 e { \mathopen {} \left ( i \right ) \mathclose {}}  & \text {when } e { \mathopen {} \left ( i \right ) \mathclose {}} \in  A \\ 
 a_0 & \text {otherwise}
 \end {cases}

\begin {aligned}
e& \colon   \mathbb {N} \twoheadrightarrow   \mathbb {Z} \\ 
e { \mathopen {} \left ( i \right ) \mathclose {}}  &=
 \begin {cases}
 0 & \text {when } i=0 \\ 
 i \div  2 & \text {when } i > 0  \land  2 \mid  i \\ 
 - { \mathopen {} \left ( i+1 \right ) \mathclose {}} \div  2 & \text {when } i > 0  \land   \lnot { \mathopen {} \left ( 2 \mid  i \right ) \mathclose {}} 
 \end {cases}
\end {aligned}

\mathord { \# } { \mathrm {Inj} { \mathopen {} \left ( A , B \right ) \mathclose {}} } =
\begin {cases}
{ \mathord { \# } {B} \choose \mathord { \# } {A}} \cdot   { \mathopen {} \left ( \mathord { \# } {A} \right ) \mathclose {}} ! & \text {when }  \mathord { \# } {A} \leq   \mathord { \# } {B}
 \\ 
0 & \text {otherwise}
\end {cases}

